@module clipboard  src=clipboard.lua  loc=488  sha=ec591ad  mode=chunk  self=clipboard
@deps ec, grid, tm, cm, currentRpb, getCtx, edit, aliases, fx

# Invariants & contracts
  @invariant  clipboard persists via REAPER ExtState under ('rdm','clipboard'), serialised by util.serialise  @ 4
  @invariant  clip rows are 0-relative to the clip's top (row=0 is first row of selection); paste re-bases against current cursor row  @ 5
  @invariant  single vs multi mode is decided by selected-col count: c1==c2 -> single, otherwise multi  @ 6
  @invariant  single.type ∈ { 'note', '7bit', 'pb' } — note/vel split decided at copy by region's part1  @ 7
  @invariant  multi.cols carry chanDelta from leftmost source channel; cursor's channel becomes the leftmost destination  @ 8
  @invariant  CLIP_RESERVED keys are stripped at copy; CLIP_ARTIFACTS (row/endRow) are stripped at paste; everything else (including custom metadata) round-trips  @ 9
  @invariant  velEvent is the only collector that synthesises a clip event rather than cloning the source — vel-mode pastes must not carry note metadata onto cc destinations  @ 10

# Imports
  @require util = 'util'  @ 11

# Private state
  @state CLIP_RESERVED = {  @ 19
  @state CLIP_ARTIFACTS = { row = true, endRow = true }  @ 30
  @state ec = deps.ec  @ 36
  @state grid = deps.grid  @ 37
  @state tm = deps.tm  @ 38
  @state cm = deps.cm  @ 39
  @state currentRpb = deps.currentRpb  @ 40
  @state getCtx = deps.getCtx  @ 41
  @state edit = deps.edit  @ 42   -- leaf-edit facade: routes add/delete/assign to gm or tm by cell kind
  @state aliases = deps.aliases  @ 43   -- (cells) -> bool: refuse a paste whose footprint aliases one group
  @state fx = deps.fx  @ 44   -- { gather(r1,r2,c1,c2,anchorChan), paste(list) }: fx regions ride the clip
  @state clipboard = {}  @ 471

# Private functions
  @fn save(clip)  @ 46-48
  @fn load()  @ 50-54
  @fn collect()  @ 57-167
      @contract  nil if the resolved selection is empty; single-col → { mode='single', type, ... }; multi-col → { mode='multi', cols=[...] }.  @ 56
  @fn refusePaste(chan, evType, lane, cc, startRow, numRows)  @ 172-179
      -- One footprint cell per destination row, fed to aliases() so a paste covering
      -- >=2 instances of one group is refused in global mode (decision 5). Mirrors the
      -- shiftEvents gate; see design/group-aware-editing.md § Injectivity predicate.
  @fn pasteVelocities(events, dstCol, startppq, endppq)  @ 182-223
      @contract  carry-forward over note-ons in region (clip val updates currentVel, then writes onto next note-ons); pass 2 may emit PA events on sustain rows when cm.polyAftertouch is set  @ 181
  @fn pasteSingle(clip)  @ 226-315
      @contract  dispatches by (clip.type, dstCol.type, cursorPart): note->note(pitch), 7bit->note(vel) via pasteVelocities, pb->pb, 7bit->cc/at/pc; mismatched combos silently no-op.  @ 225
  @fn pasteMulti(clip)  @ 318-436
      @contract  resolves each clip col against cursor's chan via chanDelta; out-of-range channels and missing destinations skip silently; bails entirely if startType=='note' but cursor isn't on a note col.  @ 317
  @fn pasteClip(clip)  @ 438-443
  @fn trimTop(clip, trim)  @ 447-467
      -- A note whose start row falls within the trimmed band is dropped entirely.
      @contract  mutates clip in place; survives both modes; used by duplicate-up at row 0 to keep selection-following behaviour cumulative  @ 445

